import{_ as a,o as t,c as d,j as e,a as p,a1 as n}from"./chunks/framework.Bp7r_-XI.js";const h=JSON.parse('{"title":"Exceed-海燕","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/Transcend Fate/Exceed-海燕.md","filePath":"4.资源分区/7.物品与装备/6.套装/Transcend Fate/Exceed-海燕.md"}'),c={name:"4.资源分区/7.物品与装备/6.套装/Transcend Fate/Exceed-海燕.md"};function s(o,r,b,l,_,i){return t(),d("div",null,[...r[0]||(r[0]=[e("h1",{id:"exceed-海燕",tabindex:"-1"},[p("Exceed-海燕 "),e("a",{class:"header-anchor",href:"#exceed-海燕","aria-label":'Permalink to "Exceed-海燕"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：绯红庆典040")])])],-1),n('<h1 id="exceed-海燕-1" tabindex="-1">Exceed-海燕 <a class="header-anchor" href="#exceed-海燕-1" aria-label="Permalink to &quot;Exceed-海燕&quot;">​</a></h1><p>Exceed-海燕<br> 描述：如同山峦般的巨鲸悬浮在城市上空，随着它开始歌唱，狂乱的气流便拔地而起。</p><p>“请各位住户关好门窗，固定窗台上花盆等易坠物品。”</p><p>“台风来了。”</p><p>云海咆哮<br> B+2500<br> 分类：霰弹枪<br> 武器伤害：19L<br> 武器特性：高速5，攻击距离不超过15米内的单位时获得2威猛，【超级贯穿】<br> 弹容量：特殊<br> 武器体积：4<br> 速射等级：连射<br> 基础射程：40米<br> 伤害类型：能量-音波<br> 概述：灾厄应对机构通过解析象征台风概念的灾厄兽【海燕】，通过对其能够唤起气流大量扰动的发声器官的理论作为核心，以AA-12为基底应用而成的霰弹枪。</p><p>云海咆哮发射的是通过发声产生的经过压缩的大量气流，因此不具有常规的弹药特性，该武器进行的攻击具有1dp器械加值，同时覆盖前方扇形射程范围内的所有敌对单位，目标使用反射豁免而非正常防御。<br> 由于大量的气流，敌人将被吹离，一轮仅一次，该武器进行的攻击命中敌对单位时，可以迫使其进行一次反射豁免对抗攻击出目，目标该次反射豁免将额外获得等同于其体积-5的表现加值，失败则迫使其远离武器持有者的方向等同于该次豁免与攻击出目的差值米。</p><p>空之挽歌<br> B+2000<br> 分类：轻甲<br> 器械防御：24/24<br> 盔甲特性：【超级坚韧】【防能量】<br> 概述：灾厄应对机构通过解析象征台风概念的灾厄兽【海燕】，通过对其表层能够抵御外部因为内部几乎真空产生的强大气压差制作而出的特种黑色防风衣。</p><p>空之挽歌由于其是通过内部的真空气囊减轻攻击带来的伤害，其提供的防御为器械防御而非盔甲防御，同时由于气囊提供的轻柔性，穿戴者免疫擒抱状态与接触攻击。</p><p>套装效果：<br> “为什么要给这头灾厄兽取名为海燕？”</p><p>“它只是一场台风，会到来，摧毁我们的家园，它亦是离巢的候鸟，来去如风”</p><p>“候鸟的到来，是福不是祸；人类文明的传承总能在风中屹立不倒，往日如是，往后亦如是”</p><p>当同时穿戴空之挽歌与持有云海咆哮时，使用者具有机动性为完美的飞行能力，移动速度提高120米。</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',14)])])}const f=a(c,[["render",s]]);export{h as __pageData,f as default};
